using HaCreator.MapEditor;using HaCreator.MapEditor.Instance;using HaCreator.MapEditor.UndoRedo;using System;using System.Collections.Generic;using System.Windows;
namespace HaCreator.GUI.InstanceEditor{public partial class ReactorInstanceEditor:EditorBase{public ReactorInstance item;public ReactorInstanceEditor(ReactorInstance item){InitializeComponent();this.item=item;InstanceEditorDialogSupport.SetInt(xInput,item.X);InstanceEditorDialogSupport.SetInt(yInput,item.Y);pathLabel.Text=HaCreatorStateManager.CreateItemDescription(item);useName.IsChecked=item.Name!=null;nameBox.Text=item.Name??string.Empty;InstanceEditorDialogSupport.SetInt(timeBox,item.ReactorTime);UseName_Changed(null,null);}protected override void cancelButton_Click(object s,EventArgs e)=>Close();protected override void okButton_Click(object s,EventArgs e){lock(item.Board.ParentControl){int x=InstanceEditorDialogSupport.GetInt(xInput,item.X),y=InstanceEditorDialogSupport.GetInt(yInput,item.Y);List<UndoRedoAction>a=new();if(x!=item.X||y!=item.Y){a.Add(UndoRedoManager.ItemMoved(item,new Microsoft.Xna.Framework.Point(item.X,item.Y),new Microsoft.Xna.Framework.Point(x,y)));item.Move(x,y);}if(a.Count>0)item.Board.UndoRedoMan.AddUndoBatch(a);item.Name=useName.IsChecked==true?nameBox.Text:null;item.ReactorTime=InstanceEditorDialogSupport.GetInt(timeBox,item.ReactorTime);}Close();}private void UseName_Changed(object s,RoutedEventArgs e){if(nameBox!=null)nameBox.IsEnabled=useName.IsChecked==true;}private void Cancel_Click(object s,RoutedEventArgs e)=>cancelButton_Click(s,EventArgs.Empty);private void Ok_Click(object s,RoutedEventArgs e)=>okButton_Click(s,EventArgs.Empty);}}
